// // This module implements a D-type flip-flop with enable functionality.
// It updates its output on the falling edge of the clock signal when the enable signal is high.
module d_ff_en(
    input D,
    input EN,
    input CLK,
    output reg Q
);

always @(posedge CLK) begin
    if (EN) begin
        Q <= D;
    end
end

endmodule
